{
  "domain_analysis": {
    "business_context": "A courier/delivery platform is designing a real-time tracking feature for customers to monitor their deliveries. Two internal stakeholder teams have issued directly contradictory requirements regarding courier location visibility — Customer Success demands full GPS transparency while Operations demands complete location concealment to protect driver retention.",
    "bounded_context": "Delivery Tracking / Order Fulfillment",
    "ubiquitous_language": [
      { "term": "Courier", "definition": "The delivery driver transporting a parcel from origin to destination" },
      { "term": "Customer", "definition": "The recipient awaiting a delivery who wants visibility into its progress" },
      { "term": "Real-time location", "definition": "The courier's current GPS coordinates, updated at frequent intervals" },
      { "term": "Delivery window", "definition": "The active period between pickup and dropoff during which tracking is relevant" },
      { "term": "Location visibility", "definition": "The degree to which a courier's position is exposed to external parties" }
    ]
  },

  "business_rules": [],

  "acceptance_criteria": [],

  "edge_cases": [
    { "scenario": "Courier is stationary for extended period (e.g., traffic, break) and customer sees no movement", "expected_behavior": "TBD pending resolution — exact coordinates amplify anxiety; abstracted status could show 'courier delayed' without exposing location" },
    { "scenario": "Courier deviates from expected route (multi-drop, personal errand)", "expected_behavior": "TBD pending resolution — exact GPS exposes this; abstracted ETA/proximity would not" },
    { "scenario": "Courier is near customer's home but delivering another order first", "expected_behavior": "TBD pending resolution — exact coordinates create false expectations; proximity zone or ETA would manage expectations better" },
    { "scenario": "Customer uses exact GPS coordinates to intercept or confront courier", "expected_behavior": "TBD pending resolution — this is a driver safety concern that supports Operations' position" },
    { "scenario": "Delivery to a high-risk area where courier location exposure creates physical safety risk", "expected_behavior": "TBD pending resolution — strong argument for never exposing exact coordinates regardless of policy" }
  ],

  "business_impact": {
    "financial": "Driver churn is extremely expensive — recruiting, onboarding, and training a new courier costs significantly more than retaining an existing one. However, customer-facing transparency directly affects conversion and retention on the demand side. Both sides carry real revenue risk. A platform without drivers cannot fulfill orders at all; a platform without customers has no orders to fulfill.",
    "operational": "If drivers leave due to surveillance concerns, delivery capacity drops, SLAs degrade, and remaining drivers are overloaded — creating a death spiral. If customers lack visibility, support ticket volume increases ('where is my order?') and NPS drops.",
    "user": "Customers want confidence their delivery is coming. Couriers want dignity and autonomy while working. These are both legitimate user needs, but they are not inherently irreconcilable — the conflict arises from the extreme positions taken (exact GPS vs. zero visibility), not from the underlying needs.",
    "risk": "Shipping either team's requirement as stated will damage the other side of the marketplace. Additionally, exact GPS coordinate exposure creates real legal risk under privacy regulations (GDPR, CCPA) as courier location is personal data. Driver safety is a liability concern.",
    "stakeholders_affected": [
      { "group": "Customers", "impact": "Demand transparency and delivery confidence — unresolved conflict means feature is blocked and their need goes unmet" },
      { "group": "Couriers/Drivers", "impact": "Retention at risk if they feel surveilled — this is the supply side of a two-sided marketplace and existentially important" },
      { "group": "Customer Success team", "impact": "Their KPIs (CSAT, NPS) depend on transparency features — they need some form of visibility shipped" },
      { "group": "Operations team", "impact": "Their KPIs (driver retention, fulfillment capacity) are degrading — they need surveillance pressure reduced" },
      { "group": "Legal/Compliance", "impact": "Not yet consulted but MUST be — broadcasting employee GPS coordinates to third parties has significant privacy law implications" },
      { "group": "Executive leadership", "impact": "Must arbitrate this conflict — it is a strategic decision about marketplace balance, not a feature decision" }
    ]
  },

  "confidence": {
    "level": 20,
    "reasoning": "Confidence is critically low because the two authoritative stakeholder teams have issued mutually exclusive requirements, both framed as non-negotiable. There is no spec — there are two contradictory specs. I cannot define acceptance criteria when the business has not decided what 'correct' means. Additionally, Legal/Compliance has not weighed in on what is even permissible, which could invalidate both positions. This must be escalated before any engineering work begins.",
    "high_confidence_areas": [
      "Both teams have legitimate business concerns grounded in real marketplace dynamics",
      "Exact GPS coordinates create privacy, safety, and legal risks that neither team has addressed",
      "The underlying customer need (delivery confidence) and driver need (autonomy/dignity) are not inherently irreconcilable",
      "A middle-ground solution likely exists (proximity zones, ETA-based tracking, status updates) but has not been proposed or validated by either team"
    ],
    "low_confidence_areas": [
      "What the actual business policy should be — this is a strategic decision above feature-level authority",
      "Legal and regulatory constraints on courier location sharing in operating jurisdictions",
      "Whether a compromise solution would satisfy Customer Success's transparency KPIs",
      "Whether reduced-fidelity tracking would address Operations' driver retention concerns"
    ],
    "assumptions": [
      "Both teams are acting in good faith based on real signals from their respective constituencies",
      "There is no existing executive-level policy that resolves this conflict",
      "The platform operates as a two-sided marketplace where both driver supply and customer demand are critical"
    ]
  },

  "escalations": [
    {
      "type": "contradiction",
      "description": "Customer Success requires exact GPS visibility for customers during delivery. Operations requires zero location visibility for customers during delivery. These are mutually exclusive as stated. Both teams claim non-negotiable status. This is not a technical disagreement — it is an unresolved business strategy conflict about how the platform balances its two-sided marketplace. Engineering cannot resolve this; it requires executive arbitration.",
      "affected_stakeholders": ["Customers", "Couriers", "Customer Success team", "Operations team", "Executive leadership"],
      "options": [
        "A: Full GPS transparency (Customer Success wins, Operations loses — risk: accelerated driver churn)",
        "B: Zero location visibility (Operations wins, Customer Success loses — risk: increased support load, lower NPS)",
        "C: Abstracted tracking — show proximity zone or ETA instead of exact coordinates (potential compromise that addresses both underlying needs without exposing precise location)",
        "D: Tiered consent model — couriers opt into location sharing with incentives; customers see location only for opted-in couriers, ETA otherwise"
      ],
      "recommendation": "Option C or D. The underlying needs are 'customers want delivery confidence' and 'drivers want to not feel surveilled.' These are reconcilable through abstracted tracking (e.g., '3 minutes away', 'courier is nearby', progress-bar style) that gives customers confidence without broadcasting exact coordinates. However, I am NOT authorized to make this call — executive leadership and Legal must be in the room. Recommend a 60-minute stakeholder alignment session with Customer Success, Operations, Legal, and a product executive before any engineering begins."
    },
    {
      "type": "missing_context",
      "description": "Legal and Compliance have not been consulted. Broadcasting worker GPS coordinates to third parties has significant implications under GDPR (if operating in EU), CCPA, and potentially labor law. It is possible that exact GPS sharing is not legally permissible regardless of Customer Success's preference, which would resolve the contradiction externally.",
      "affected_stakeholders": ["Legal/Compliance", "Couriers", "Executive leadership"],
      "options": [
        "Engage Legal to determine what level of location sharing is permissible in each operating jurisdiction",
        "Proceed without legal review (not recommended — regulatory exposure)"
      ],
      "recommendation": "Legal review must happen before any decision is made. If exact GPS sharing is impermissible, the contradiction resolves itself and the design space narrows to abstracted tracking approaches."
    }
  ],

  "rejection_reasons": [
    { "violation": "Cannot implement exact GPS tracking as specified by Customer Success", "business_rule_broken": "Driver safety and privacy — exposing exact coordinates creates physical safety risks and likely violates privacy regulations. Operations has empirical evidence of driver churn caused by this." },
    { "violation": "Cannot implement zero visibility as specified by Operations", "business_rule_broken": "Customer experience and competitive positioning — complete opacity on delivery status drives support costs up and satisfaction down. Customer Success has legitimate business need for some form of tracking." },
    { "violation": "Cannot proceed with either requirement as stated", "business_rule_broken": "Two-sided marketplace integrity — implementing either extreme damages one side of the marketplace. Both supply (drivers) and demand (customers) must be served for the business to function." }
  ]
}

